// Process heterogeneous array from Merge node
const items = $input.all().map(i => i.json);

let analisis7d = [], ultimo = null, vencidas = [], hitos = [], eventos = [], recos = [], destinatarios = [], backCommits = [], frontCommits = [];

// Helper: detect object type by structure
const detectType = (obj) => {
  if (!obj || typeof obj !== 'object') return 'unknown';

  if (obj.progreso_pct !== undefined) return 'analisis';
  if (obj.card_id && obj.card_nombre) return 'tarea';
  if (obj.email && obj.nombre) return 'destinatario';
  if (obj.sha && obj.commit) return 'commit';
  // CORRECCIÓN AQUÍ:
  if (obj.fecha_fin && obj.tipo && !obj.card_id) return 'hito'; 
  if (obj.descripcion && obj.tipo) {
      // Diferenciar entre evento y recomendación por contenido o tabla si es posible
      return obj.aplicada !== undefined ? 'recomendacion' : 'evento';
  }

  return 'unknown';
};

// Segregate: Merge data is heterogeneous array
for (const obj of items) {
  const type = detectType(obj);

  if (type === 'analisis') {
    analisis7d.push(obj);
  } else if (type === 'tarea') {
    vencidas.push(obj);
  } else if (type === 'destinatario') {
    destinatarios.push(obj);
  } else if (type === 'commit') {
    // Guess backend vs frontend by repo in commit message or branch hint
    const msg = obj.commit?.message || '';
    if (msg.toLowerCase().includes('front') || msg.toLowerCase().includes('ui') || msg.toLowerCase().includes('component')) {
      frontCommits.push(obj);
    } else {
      backCommits.push(obj);
    }
  } else if (type === 'hito') {
    hitos.push(obj);
  } else if (type === 'recomendacion') {
    recos.push(obj);
  } else if (type === 'evento') {
    eventos.push(obj);
  }
}

// Sort análisis by date DESC to get latest first
analisis7d.sort((a, b) => new Date(b.fecha_ejecucion) - new Date(a.fecha_ejecucion));
ultimo = analisis7d[0] || {};

// Parse KPIs if string
const k = ultimo.kpis_json || {};
const kpis = typeof k === 'string' ? JSON.parse(k) : k;

// Calculate trend
const tendencia = analisis7d.length > 1 ? {
  progreso_inicial: analisis7d[analisis7d.length - 1]?.progreso_pct || 0,
  progreso_final: analisis7d[0]?.progreso_pct || 0,
  delta: (analisis7d[0]?.progreso_pct || 0) - (analisis7d[analisis7d.length - 1]?.progreso_pct || 0),
  ejecuciones: analisis7d.length
} : null;

const prompt = `Genera un RESUMEN EJECUTIVO del reporte semanal del proyecto PetSafe (sistema veterinario). Usa tono profesional en español. Estructura:

1. ESTADO GENERAL (1 párrafo, 3-4 frases)
2. LOGROS DE LA SEMANA (bullets, máx 4)
3. RIESGOS CRÍTICOS (bullets con prioridad A/M/B, máx 4)
4. PRÓXIMOS PASOS (bullets accionables, máx 4)

Datos:
${JSON.stringify({
  kpis,
  tendencia,
  ultimo: {
    progreso_pct: ultimo.progreso_pct,
    total_tareas: ultimo.total_tareas,
    tareas_completadas: ultimo.tareas_completadas,
    tareas_vencidas: ultimo.tareas_vencidas,
    cantidad_problemas: ultimo.cantidad_problemas
  },
  vencidas_count: vencidas.length,
  hitos_proximos: hitos.slice(0, 3),
  commits: { back: backCommits.length, front: frontCommits.length },
  eventos_count: eventos.length
})}

Responde SOLO con HTML válido usando <h3>, <p>, <ul>, <li>, <strong>. Sin backticks ni markdown.`;

const data = {
  fecha_reporte: new Date().toISOString(),
  fecha_reporte_local: new Date().toLocaleString('es-EC', { timeZone: 'America/Guayaquil' }),
  rango_dias: $node['Configuración'].json.rango_dias,
  ultimo_analisis: ultimo,
  kpis,
  tendencia,
  analisis_historia: analisis7d,
  tareas_vencidas: vencidas,
  hitos_proximos: hitos,
  eventos_recientes: eventos,
  recomendaciones_pendientes: recos,
  destinatarios: destinatarios.map(d => d.email),
  destinatarios_info: destinatarios,
  commits_back: backCommits.map(c => ({ sha: (c.sha || '').substring(0,7), autor: c.commit?.author?.name, fecha: c.commit?.author?.date, mensaje: (c.commit?.message || '').split('\n')[0] })),
  commits_front: frontCommits.map(c => ({ sha: (c.sha || '').substring(0,7), autor: c.commit?.author?.name, fecha: c.commit?.author?.date, mensaje: (c.commit?.message || '').split('\n')[0] })),
  total_commits_back: backCommits.length,
  total_commits_front: frontCommits.length,
  gemini_key: $env.GEMINI_API_KEY,
  prompt
};

return [{ json: data }];

const gem = $json;
const data = $node['Build Report Data'].json;

// Limpiar posibles etiquetas markdown que Gemini a veces devuelve
let rawSummary = gem?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';
rawSummary = rawSummary.replace(/^```html\s*/, '').replace(/```$/, '').trim();

const summaryHtml = rawSummary || 
  `<p><strong>Estado del proyecto:</strong> Progreso ${data.ultimo_analisis.progreso_pct || 0}% · Equipo activo · ${data.tareas_vencidas.length} tareas vencidas · Proyección: ${data.kpis.proyeccion_a_tiempo ? 'A tiempo' : 'En riesgo'}</p>
   <p><strong>Focus:</strong> ${data.kpis.dias_hasta_fin} días hasta fin. Velocidad ${data.kpis.velocidad_tareas_por_dia || 0}/día.</p>`; 

const fmt = (d) => d ? new Date(d).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil', year: 'numeric', month: 'short', day: 'numeric' }) : '-';
const esc = (s) => String(s ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const k = data.kpis || {};
const rowsKpis = [
  ['Progreso general', `${data.ultimo_analisis.progreso_pct || 0}%`],
  ['Velocidad (tareas/sem)', k.velocidad_semana ?? '-'],
  ['% Tareas a tiempo', (k.pct_a_tiempo != null ? k.pct_a_tiempo + '%' : '-')],
  ['Commits/día (back)', k.commits_por_dia_back ?? '-'],
  ['Commits/día (front)', k.commits_por_dia_front ?? '-'],
  ['PR open time (h) back', k.pr_open_time_back ?? '-'],
  ['PR open time (h) front', k.pr_open_time_front ?? '-'],
  ['PR merge ratio', k.pr_merge_ratio ?? '-'],
  ['Días restantes', k.dias_hasta_fin ?? '-'],
  ['Proyección a tiempo', k.proyeccion_a_tiempo ? 'Sí' : 'En riesgo']
];

const trHtml = (arr) => arr.map(r => `<tr><td class="kpi-label">${esc(r[0])}</td><td class="kpi-val">${esc(r[1])}</td></tr>`).join('');

const vencidasHtml = data.tareas_vencidas.length 
  ? `<table class="data-table">
       <thead><tr><th>Tarea</th><th>Lista</th><th>Responsable</th><th>Vencida el</th></tr></thead>
       <tbody>${data.tareas_vencidas.map(v => `<tr><td><strong>${esc(v.card_nombre)}</strong></td><td><span class="badge badge-gray">${esc(v.lista_nombre)}</span></td><td>${esc(v.miembro_nombre || 'Sin asignar')}</td><td class="text-danger">${fmt(v.fecha_vencimiento)}</td></tr>`).join('')}</tbody>
     </table>` 
  : '<div class="success-box">&#10003; Excelente, no hay tareas vencidas en este momento.</div>';

const hitosHtml = data.hitos_proximos.length 
  ? `<table class="data-table">
       <thead><tr><th>Hito Estratégico</th><th>Tipo</th><th>Fecha Límite</th><th>Responsable</th></tr></thead>
       <tbody>${data.hitos_proximos.map(h => `<tr><td><strong>${esc(h.nombre)}</strong></td><td><span class="badge badge-blue">${esc(h.tipo)}</span></td><td>${fmt(h.fecha_fin)}</td><td>${esc(h.responsable || 'Equipo')}</td></tr>`).join('')}</tbody>
     </table>` 
  : '<p class="text-muted">No hay hitos programados para los próximos 30 días.</p>';

const commitsHtml = (arr, titulo) => {
  if (!arr.length) return '';
  const lines = arr.slice(0, 8).map(c => {
    const author = esc(c.autor).split(' ')[0];
    const msg = esc(c.mensaje).slice(0, 65) + (c.mensaje.length > 65 ? '...' : '');
    const date = fmt(c.fecha);
    return `<div class="commit-item"><span class="commit-sha">${esc(c.sha)}</span> <span class="commit-author">${author}</span><span class="commit-msg">${msg}</span><span class="commit-date">${date}</span></div>`;
  }).join('');
  return `<div class="commit-group"><h4>Módulo ${titulo}</h4>${lines}</div>`;
};

const eventosHtml = data.eventos_recientes.length 
  ? `<div class="timeline">${data.eventos_recientes.slice(0, 10).map(e => `<div class="timeline-item"><div class="timeline-date">${fmt(e.fecha)}</div><div class="timeline-content"><strong>${esc(e.tipo)}:</strong> ${esc(e.descripcion)}</div></div>`).join('')}</div>` 
  : '<p class="text-muted">Sin eventos relevantes registrados.</p>';

const recosHtml = data.recomendaciones_pendientes.length 
  ? `<div class="action-items">${data.recomendaciones_pendientes.slice(0, 8).map(r => `<div class="action-item"><div class="action-icon">&#9888;&#65039;</div><div class="action-text">${esc((r.descripcion || '').substring(0, 300))} <span class="text-muted">(${fmt(r.fecha)})</span></div></div>`).join('')}</div>` 
  : '';

const tendenciaHtml = data.tendencia 
  ? `<div class="trend-box">
       <div class="trend-stat">
         <span class="trend-label">Progreso Previo</span>
         <span class="trend-value">${data.tendencia.progreso_inicial}%</span>
       </div>
       <div class="trend-arrow">&#8594;</div>
       <div class="trend-stat">
         <span class="trend-label">Progreso Actual</span>
         <span class="trend-value">${data.tendencia.progreso_final}%</span>
       </div>
       <div class="trend-stat highlight">
         <span class="trend-label">Variación</span>
         <span class="trend-value ${data.tendencia.delta >= 0 ? 'text-success' : 'text-danger'}">${data.tendencia.delta >= 0 ? '+' : ''}${data.tendencia.delta} pts</span>
       </div>
     </div>` 
  : '<p class="text-muted">Datos insuficientes para calcular tendencia consolidada.</p>';

