const fileName = `reporte-petsafe-${new Date().toISOString().slice(0,10)}.html`;
const summaryText = `Reporte semanal PetSafe: progreso ${data.ultimo_analisis.progreso_pct || 0}%, ${data.tareas_vencidas.length} tareas vencidas, ${data.total_commits_back + data.total_commits_front} commits, ${data.eventos_recientes.length} eventos.`;

return [{
  json: {
    summaryText,
    destinatarios: data.destinatarios,
    destinatarios_info: data.destinatarios_info,
    rango_dias: data.rango_dias,
    fecha_reporte_local: data.fecha_reporte_local
  },
  binary: {
    data: {
      data: Buffer.from(html).toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const meta = $node['Build HTML + Binary'].json;
const fileName = `reporte-petsafe-${new Date().toISOString().slice(0,10)}.pdf`;
const pdfBin = $binary.pdf;
return [{
  json: { ...meta, fileName },
  binary: { pdf: { ...pdfBin, fileName, mimeType: 'application/pdf' } }
}];
